'use client';

import { AdminNav } from '@/components/AdminNav';
import { RequireAuth } from '@/components/RequireAuth';
import { adminApi } from '@/lib/api';
import { useState } from 'react';

export default function KitchenPage() {
  const [orderId, setOrderId] = useState(0);
  const [msg, setMsg] = useState('');

  async function update(status: string) {
    await adminApi.orderStatus(orderId, status);
    setMsg(`Order ${orderId} -> ${status}`);
  }

  return (
    <RequireAuth>
      <main>
        <AdminNav />
        <div className="card">
          <h1>Kitchen Board</h1>
          <input type="number" value={orderId} onChange={(e) => setOrderId(Number(e.target.value))} placeholder="Order ID" />
          <div className="grid2" style={{ marginTop: 8 }}>
            <button onClick={() => update('preparing')}>new -&gt; preparing</button>
            <button onClick={() => update('ready')}>preparing -&gt; ready</button>
          </div>
          <p className="small">{msg}</p>
        </div>
      </main>
    </RequireAuth>
  );
}

